events.onClick:
if (!ctx.getValue('姓名') && ctx.getValue('姓名') !== 0) return ctx.showMessage('请填写姓名', 'error');
if (!ctx.getValue('班级') && ctx.getValue('班级') !== 0) return ctx.showMessage('请填写班级', 'error');
if (!ctx.getValue('语文') && ctx.getValue('语文') !== 0) return ctx.showMessage('请填写语文', 'error');
if (!ctx.getValue('数学') && ctx.getValue('数学') !== 0) return ctx.showMessage('请填写数学', 'error');
if (!ctx.getValue('英语') && ctx.getValue('英语') !== 0) return ctx.showMessage('请填写英语', 'error');
if (!ctx.getValue('出勤率') && ctx.getValue('出勤率') !== 0) return ctx.showMessage('请填写出勤率', 'error');
let currentId = Number(ctx.getValue('学号') || 0);
if (!currentId) {
  currentId = (() => { const rows = ctx.querySheet('students');
const maxId = rows.reduce((max, row) => Math.max(max, Number(row?.学号) || 0), 0);
return maxId + 1; })();
  await ctx.setValue('学号', currentId);
}
const total = Number(ctx.getValue('语文') || 0) + Number(ctx.getValue('数学') || 0) + Number(ctx.getValue('英语') || 0);
const attendance = Number(ctx.getValue('出勤率') || 0);
const risk = total < 240 || attendance < 90 ? '高' : total < 285 || attendance < 95 ? '中' : '低';
await ctx.setValue('风险等级', risk);
await ctx.runConfiguredWorkflow();
const nextId = (() => { const rows = ctx.querySheet('students');
const maxId = rows.reduce((max, row) => Math.max(max, Number(row?.学号) || 0), 0);
return maxId + 1; })();
await ctx.setValue('学号', nextId);
await ctx.setValue('班级', "高一(1)班");
await ctx.setValue('风险等级', "低");
await ctx.setValue('出勤率', 95);
await ctx.setValue('姓名', '');
await ctx.setValue('语文', '');
await ctx.setValue('数学', '');
await ctx.setValue('英语', '');
await ctx.setValue('状态提示', '表单已重置，可继续录入。');
await ctx.showMessage(`学生信息已新增：${currentId}`, 'success');

const nextId = (() => { const rows = ctx.querySheet('students');
const maxId = rows.reduce((max, row) => Math.max(max, Number(row?.学号) || 0), 0);
return maxId + 1; })();
await ctx.setValue('学号', nextId);
